import React, { useEffect, useState } from "react";
import {
  Table,
  Modal,
  Input,
  Button,
  Tag,
  Space,
  Badge,
  Tooltip,
  Typography,
} from "antd";
import { useDispatch, useSelector } from "react-redux";
import {
  getNotApprovedProducts,
  deleteAProduct,
} from "../../features/product/productSlice";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import { useNavigate } from "react-router-dom";
import {
  BiEdit,
  BiSearch,
  BiTrash,
  BiShow,
  BiInfoCircle,
} from "react-icons/bi";
import { AiOutlineCloseCircle } from "react-icons/ai";

const { TextArea } = Input;
const { Text } = Typography;

const RejectedProduct = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [openRejectionModal, setOpenRejectionModal] = useState(false);
  const [selectedRejectionReason, setSelectedRejectionReason] = useState("");
  const [selectedSuggested_Changes, setSelectedSuggested_Changes] =
    useState("");
  const [selectedRejectionDate, setSelectedRejectionDate] = useState("");
  const [searchText, setSearchText] = useState("");
  const status = "rejected";

  useEffect(() => {
    dispatch(getNotApprovedProducts(status));
  }, [dispatch]);

  const user = useSelector((state) => state?.auth?.user);
  const products = useSelector(
    (state) => state?.product?.pendingProducts || [],
  );

  const handleViewRejectionReason = (rejectionReason) => {
    setSelectedRejectionReason(
      rejectionReason?.Reason || "Compliance deviation details unspecified.",
    );
    setSelectedSuggested_Changes(
      rejectionReason?.Suggested_Changes ||
        "Standard operational adjustment required.",
    );
    setSelectedRejectionDate(rejectionReason?.Rejection_Date || "N/A");
    setOpenRejectionModal(true);
  };

  const handleDelete = (productId) => {
    dispatch(deleteAProduct({ productId, userId: user?._id }))
      .then(() => {
        toast.success("Listing Terminated Successfully");
        dispatch(getNotApprovedProducts(status));
      })
      .catch(() => {
        toast.error("Listing Termination Failed");
      });
  };

  const columns = [
    {
      title: "#ORDINAL",
      dataIndex: "key",
      render: (text) => (
        <span className="font-mono text-[10px] font-black text-gray-400">
          PRD-{text}
        </span>
      ),
      width: 100,
    },
    {
      title: "PRODUCT IDENTITY (NAME)",
      dataIndex: "title",
      render: (text) => (
        <span className="font-black text-gray-900 tracking-tight uppercase text-xs">
          {text}
        </span>
      ),
      sorter: (a, b) => a.title.localeCompare(b.title),
    },
    {
      title: "CLASSIFICATION",
      dataIndex: "category",
      render: (text, record) => (
        <Space direction="vertical" size={0}>
          <span className="text-gray-500 font-medium text-[11px] uppercase tracking-tight">
            {text}
          </span>
          <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
            {record.brand}
          </span>
        </Space>
      ),
    },
    {
      title: "LIFECYCLE STATUS",
      dataIndex: "ProductApproved",
      render: () => (
        <Badge
          status="error"
          text={
            <span className="text-red-600 font-black uppercase tracking-widest text-[10px]">
              Compliance Violation
            </span>
          }
        />
      ),
    },
    {
      title: "COMPLIANCE INTEL",
      dataIndex: "rejectionReason",
      render: (_, record) => (
        <Button
          type="link"
          size="small"
          icon={<BiInfoCircle />}
          onClick={() => handleViewRejectionReason(record.rejectionReason)}
          className="text-blue-600 font-bold uppercase tracking-tight text-[10px]"
        >
          View Discrepancy
        </Button>
      ),
    },
    {
      title: "OPERATIONAL ACTIONS",
      dataIndex: "action",
      render: (_, record) => (
        <Space size="middle">
          <Tooltip title="Revise Listing">
            <Button
              type="text"
              icon={<BiEdit size={18} />}
              onClick={() => navigate(`/merchant/product/${record._id}`)}
              className="text-gray-400 hover:text-blue-600"
            />
          </Tooltip>
          <Tooltip title="Terminate Listing">
            <Button
              type="text"
              danger
              icon={<BiTrash size={18} />}
              onClick={() => handleDelete(record._id)}
            />
          </Tooltip>
        </Space>
      ),
    },
  ];

  const tableData = products
    .filter(
      (p) =>
        !searchText || p.title.toLowerCase().includes(searchText.toLowerCase()),
    )
    .map((product, index) => ({
      ...product,
      key: index + 1,
    }));

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500 bg-[#f7f7f8] min-h-screen">
      {/* Header Section */}
      <div className="flex justify-between items-end border-b border-gray-200 pb-6">
        <div>
          <h1 className="text-3xl font-black tracking-tight text-red-600">
            Compliance Violation Registry
          </h1>
          <p className="text-gray-500 font-medium tracking-tight uppercase text-xs mt-1">
            Non-Compliant Listings • Rectification Hub
          </p>
        </div>
        <div className="flex gap-4">
          <Input
            prefix={<BiSearch className="text-gray-400" />}
            placeholder="Filter Non-Compliant Items..."
            className="rounded-xl border-gray-100 w-72 h-11 shadow-sm"
            onChange={(e) => setSearchText(e.target.value)}
          />
        </div>
      </div>

      <div className="enterprise-card bg-white p-4">
        <Table
          columns={columns}
          dataSource={tableData}
          pagination={{
            pageSize: 10,
            className: "enterprise-pagination",
          }}
          className="enterprise-table"
        />
      </div>

      {/* Rejection Reason Modal */}
      <Modal
        title={
          <div className="flex items-center gap-2 text-red-600 py-2 border-b border-gray-100">
            <AiOutlineCloseCircle size={24} />
            <span className="font-black uppercase tracking-wider text-sm">
              Discrepancy Analysis Report
            </span>
          </div>
        }
        open={openRejectionModal}
        onCancel={() => setOpenRejectionModal(false)}
        footer={[
          <Button
            key="close"
            onClick={() => setOpenRejectionModal(false)}
            className="rounded-xl font-bold px-8"
          >
            Acknowledge Discrepancy
          </Button>,
        ]}
        width={650}
        className="enterprise-modal"
      >
        <div className="py-6 space-y-8">
          <div className="space-y-3">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-red-500" />{" "}
              Compliance Deviation Summary
            </label>
            <div className="bg-red-50/50 p-6 rounded-2xl border border-red-50">
              <Text className="text-gray-700 font-medium leading-relaxed italic">
                "{selectedRejectionReason}"
              </Text>
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-blue-500" />{" "}
              Mandatory Rectification Protocol
            </label>
            <div className="bg-blue-50/30 p-6 rounded-2xl border border-blue-50">
              <Text className="text-gray-700 font-medium leading-relaxed uppercase text-[11px] tracking-tight">
                {selectedSuggested_Changes}
              </Text>
            </div>
          </div>

          <div className="flex justify-between items-center pt-6 border-t border-gray-50">
            <div className="flex items-center gap-2">
              <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest leading-none">
                Detection Timestamp
              </span>
              <Tag className="rounded-full border-none bg-gray-100 text-gray-500 font-mono text-[10px]">
                {selectedRejectionDate}
              </Tag>
            </div>
            <Text className="text-[10px] text-gray-400 italic">
              Please revise listing specifications to re-initiate verification.
            </Text>
          </div>
        </div>
      </Modal>

      <ToastContainer />
    </div>
  );
};

export default RejectedProduct;
